Base Code (Starter Logic: JSON Status API + Dashboard HTML)
Backend Python (status_api.py):
from flask import Flask, jsonify
import psutil
import time
app = Flask(__name__)
start_time = time.time()
@app.route('/status')
def status():
    uptime = int(time.time() - start_time)
    cpu = psutil.cpu_percent(interval=1)
    ram = round(psutil.virtual_memory().used / (1024**3), 2)
    return jsonify({
        "status": "online",
        "uptime": uptime,
        "cpu": cpu,
        "ram": ram,
        "credits": round(uptime * 0.001, 3)
    })
app.run(port=8000)
Frontend (dashboard.html):
<script>
setInterval(() => {
  fetch('http://localhost:8000/status')
    .then(response => response.json())
    .then(data => {
      document.getElementById('uptime').innerText = data.uptime + "s";
      document.getElementById('cpu').innerText = data.cpu + "%";
      document.getElementById('ram').innerText = data.ram + " GB";
      document.getElementById('credits').innerText = data.credits;
    });
}, 5000);
</script>
